class AsyncLogEmitter:
    def __init__(self, app: ElasticApp, batch_size: int = 200, flush_interval: float = 2.0, max_queue: int = 5000):
        self.app = app
        self.batch_size = int(batch_size)
        self.flush_interval = float(flush_interval)
        self.q: "queue.Queue[Dict[str, Any]]" = queue.Queue(maxsize=max_queue)
        self._stop = threading.Event()
        self._thread = threading.Thread(target=self._run, name="AsyncLogEmitter", daemon=True)
        self._last_flush = time.time()

    def start(self) -> None:
        if not self._thread.is_alive():
            self._thread.start()

    def stop(self, timeout: float = 5.0) -> None:
        self._stop.set()
        self._thread.join(timeout=timeout)
        self.flush()

    def emit(self, event: Dict[str, Any]) -> None:
        try:
            self.q.put_nowait(event)
        except queue.Full:
            pass

    def flush(self) -> None:
        batch = []
        while True:
            try:
                batch.append(self.q.get_nowait())
            except queue.Empty:
                break
        if batch:
            self.app.bulk_log_events(batch, refresh=False)

    def _run(self) -> None:
        buffer: List[Dict[str, Any]] = []
        while not self._stop.is_set():
            try:
                item = self.q.get(timeout=0.25)
                buffer.append(item)
            except queue.Empty:
                pass

            now = time.time()
            should_flush = (len(buffer) >= self.batch_size) or (buffer and (now - self._last_flush) >= self.flush_interval)
            if should_flush:
                try:
                    self.app.bulk_log_events(buffer, refresh=False)
                except Exception:
                    pass
                buffer.clear()
                self._last_flush = now

        if buffer:
            try:
                self.app.bulk_log_events(buffer, refresh=False)
            except Exception:
                pass


def _print_json(data: Any) -> None:
    json.dump(data, sys.stdout, indent=2, ensure_ascii=False, default=str)
    sys.stdout.write("\n")
    sys.stdout.flush()


def main(argv: List[str]) -> int:
    import argparse

    parser = argparse.ArgumentParser(description="Centralized logging and search platform (Elasticsearch)")
    parser.add_argument("--host", default="http://localhost:9200", help="Elasticsearch URL")
    parser.add_argument("--docs-index", default="docs", help="Documents index name")
    parser.add_argument("--logs-prefix", default="logs", help="Logs index prefix (logs-YYYY.MM.DD)")
    sub = parser.add_subparsers(dest="cmd", required=True)

    sub.add_parser("ping")

    p_ensure = sub.add_parser("ensure-indices")

    p_doc_index = sub.add_parser("index-doc")
    p_doc_index.add_argument("--id", default=None)
    p_doc_index.add_argument("--title", required=True)
    p_doc_index.add_argument("--body", required=True)
    p_doc_index.add_argument("--tags", default="")
    p_doc_index.add_argument("--source", default="app")
    p_doc_index.add_argument("--metadata", default="{}")
    p_doc_index.add_argument("--refresh", action="store_true")

    p_doc_search = sub.add_parser("search-docs")
    p_doc_search.add_argument("--q", required=True)
    p_doc_search.add_argument("--tags", default="")
    p_doc_search.add_argument("--source", default=None)
    p_doc_search.add_argument("--from", dest="from_", type=int, default=0)
    p_doc_search.add_argument("--size", type=int, default=10)
    p_doc_search.add_argument("--no-highlight", action="store_true")

    p_log = sub.add_parser("log")
    p_log.add_argument("--message", required=True)
    p_log.add_argument("--level", default="INFO")
    p_log.add_argument("--logger", default="app")
    p_log.add_argument("--service", default="central-platform")
    p_log.add_argument("--env", default=None)
    p_log.add_argument("--event", default=None)
    p_log.add_argument("--trace-id", default=None)
    p_log.add_argument("--request-id", default=None)
    p_log.add_argument("--labels", default="{}")
    p_log.add_argument("--fields", default="{}")
    p_log.add_argument("--refresh", action="store_true")

    p_log_search = sub.add_parser("search-logs")
    p_log_search.add_argument("--q", default="")
    p_log_search.add_argument("--level", default=None, help="Level or comma-separated levels")
    p_log_search.add_argument("--service", default=None)
    p_log_search.add_argument("--logger", default=None)
    p_log_search.add_argument("--env", default=None)
    p_log_search.add_argument("--host", default=None)
    p_log_search.add_argument("--trace-id", default=None)
    p_log_search.add_argument("--request-id", default=None)
    p_log_search.add_argument("--start", default=None, help="ISO8601 (e.g. 2026-01-01T00:00:00Z)")
    p_log_search.add_argument("--end", default=None)
    p_log_search.add_argument("--from", dest="from_", type=int, default=0)
    p_log_search.add_argument("--size", type=int, default=50)
    p_log_search.add_argument("--sort", default="desc", choices=["asc", "desc"])

    p_agg = sub.add_parser("aggregate-logs")
    p_agg.add_argument("--start", default=None)
    p_agg.add_argument("--end", default=None)
    p_agg.add_argument("--interval", default="1h")
    p_agg.add_argument("--group-by", default="", help="Comma-separated fields: service,logger,host,env,event,level")
    p_agg.add_argument("--service", default=None)
    p_agg.add_argument("--env", default=None)
    p_agg.add_argument("--q", default=None)
    p_agg.add_argument("--size-terms", type=int, default=20)

    args = parser.parse_args(argv)

    cfg = ElasticConfig(hosts=[args.host])
    app = ElasticApp(cfg, docs_index=args.docs_index, logs_index_prefix=args.logs_prefix)

    if args.cmd == "ping":
        _print_json({"ok": app.ping()})
        return 0

    if args.cmd == "ensure-indices":
        app.ensure_indices()
        _print_json({"ok": True})
        return 0

    if args.cmd == "index-doc":
        app.ensure_indices()
        tags = [t for t in args.tags.split(",") if t.strip()] if args.tags else []
        metadata = json.loads(args.metadata) if args.metadata else {}
        resp = app.index_document(
            title=args.title,
            body=args.body,
            tags=tags,
            source=args.source,
            metadata=metadata,
            doc_id=args.id,
            refresh=args.refresh,
        )
        _print_json(resp)
        return 0

    if args.cmd == "search-docs":
        app.ensure_indices()
        tags = [t for t in args.tags.split(",") if t.strip()] if args.tags else None
        resp = app.search_documents(
            query=args.q,
            tags=tags,
            source=args.source,
            from_=args.from_,
            size=args.size,
            highlight=not args.no_highlight,
        )
        _print_json(resp)
        return 0

    if args.cmd == "log":
        app.ensure_indices()
        labels = json.loads(args.labels) if args.labels else {}
        fields = json.loads(args.fields) if args.fields else {}
        resp = app.log_event(
            message=args.message,
            level=args.level,
            logger=args.logger,
            service=args.service,
            env=args.env,
            event=args.event,
            trace_id=args.trace_id,
            request_id=args.request_id,
            labels=labels,
            fields=fields,
            refresh=args.refresh,
        )
        _print_json(resp)
        return 0

    if args.cmd == "search-logs":
        app.ensure_indices()
        lvl: Optional[Union[str, List[str]]] = args.level
        if isinstance(lvl, str) and "," in lvl:
            lvl = [v.strip() for v in lvl.split(",") if v.strip()]
        resp = app.search_logs(
            query=args.q,
            level=lvl,
            service=args.service,
            logger=args.logger,
            env=args.env,
            host=args.host,
            trace_id=args.trace_id,
            request_id=args.request_id,
            start=args.start,
            end=args.end,
            from_=args.from_,
            size=args.size,
            sort=args.sort,
        )
        _print_json(resp)
        return 0

    if args.cmd == "aggregate-logs":
        app.ensure_indices()
        group_by = [g.strip() for g in (args.group_by or "").split(",") if g.strip()]
        resp = app.aggregate_logs(
            start=args.start,
            end=args.end,
            interval=args.interval,
            group_by=group_by or None,
            service=args.service,
            env=args.env,
            query=args.q,
            size_terms=args.size_terms,
        )
        _print_json(resp)
        return 0

    return 2


if __name__ == "__main__":
    def _handle_sigterm(signum, frame):
        raise SystemExit(0)

    signal.signal(signal.SIGTERM, _handle_sigterm)
    raise SystemExit(main(sys.argv[1:]))